{{(() => {
  const schema = getFormSchema.data;
  if (!schema || !schema.fields) return {"placeholder": "Chọn task từ danh sách bên trái"};
  const formSource = {};
  schema.fields.forEach(field => {
    switch(field.type) {
      case 'TEXT':
      case 'TEXTAREA':
        formSource[field.id] = '';
        break;
      case 'NUMBER':
        formSource[field.id] = 0;
        break;
      case 'DROPDOWN':
      case 'RADIO':
        formSource[field.id] = '';
        break;
      case 'DATE':
        formSource[field.id] = '';
        break;
      case 'CHECKBOX':
        formSource[field.id] = false;
        break;
      default:
        formSource[field.id] = '';
    }
  });
  return formSource;
})()}}

